using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" by default; existing 500K docs use "Discriminator",
            // and raw SQL queries reference c.Discriminator.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id synthesis changed.
            // EF Core 9 maps the PK directly to the JSON "id" property as just the key value.
            // Existing docs have "id":"Product|123" and a separate "Id":123 JSON property.
            // Keep the PK mapped to uppercase "Id" and synthesize "id" in the legacy format.
            b.Property(p => p.Id).ToJsonProperty("Id");
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for Cosmos.
            // Cosmos DB doesn't support EF-managed indexes; this was silently ignored in EF8.
            // REMOVED: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 id format: "{Discriminator}|{PrimaryKey}".
/// Required so EF Core 9 can read/write documents created by EF Core 8.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    protected override string NextValue(EntityEntry entry)
        => $"{entry.Metadata.GetDiscriminatorValue()}|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

