class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous LINQ operators removed.
    // EF Core 9 Cosmos provider throws InvalidOperationException for
    // ToList(), First(), Single(), etc. Use async counterparts instead.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved the "Discriminator" property name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

